mcqs.question:
What will be the output of the following code?

class Base {};
class Derived : public Base {};

int main {
 try {
 throw Derived;
 }
 catch (Base& b) {
 cout << "Base caught";
 }
 catch (Derived& d) {
 cout << "Derived caught";
 }
}

What is the output of this code?

void func {
 throw std::runtime_error("Error");
}

int main {
 try {
 func;
 }
 catch (const std::exception& e) {
 cout << e.what;
 }
}

What is the output?

try {
 throw 10;
}
catch(...) {
 cout << "caught";
}
catch(int) {
 cout << "int caught";
}

What is the output?

class E1 : public std::exception {};
class E2 : public E1 {};

try { throw E2; }
catch(E1& e) { cout << "1"; }
catch(E2& e) { cout << "2"; }
